if (args.refetch) {
  const url = args.openapi_url!;
  console.log(`Fetching spec from ${url}...`);
  const res = await fetch(url);
  if (!res.ok) {
    console.error(`Failed to fetch: ${res.status} ${res.statusText}`);
    process.exit(1);
  }
  writeFileSync(specPath, await res.text());
